CREATE TABLE t (
  id integer,
  fid1 integer REFERENCES other(id) ON DELETE NO ACTION,
  fid2 integer REFERENCES other(id) ON DELETE RESTRICT,
  fid3 integer REFERENCES other(id) ON DELETE SET NULL,
  fid4 integer REFERENCES other(id) ON DELETE SET DEFAULT
);
ALTER TABLE t ADD CONSTRAINT fk FOREIGN KEY (fid1) REFERENCES other(id) ON DELETE RESTRICT;
ALTER TABLE t ADD CONSTRAINT fk2 FOREIGN KEY (fid2) REFERENCES other(id) ON UPDATE CASCADE ON DELETE SET NULL;
